	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('employees_designation_table');
	if($hasSelectedId) {
		$jdata = get_joined_record('employees_designation_table', $selectedId);
		if($jdata === false) $jdata = get_defaults('employees_designation_table');
		$rdata = $row;
	}
	$templateCode .= loadView('employees_designation_table-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: employees_designation_table_dv
	if(function_exists('employees_designation_table_dv')) {
		$args = [];
		employees_designation_table_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}